mapper.select:
select distinct ss.staff_id, ss.staff_number, ss.staff_position, ss.license_number, su.user_id, su.nick_name,bas.time_config from sys_user su left join sys_staff ss on(su.user_id=ss.user_id) left join sys_user_role sur on(su.user_id=sur.user_id) left join sys_role sr on(sr.role_id=sur.role_id) left join building_area_staff bas on(su.user_id = bas.user_id) inner join sys_dept d on(su.dept_id = d.dept_id)
sr.role_key NOT LIKE '%admin%' and bas.id is not null
${params.dataScope}

select distinct ss.staff_id, ss.staff_number, ss.staff_position, ss.license_number, su.user_id, su.nick_name,bas.time_config from sys_user su left join sys_staff ss on(su.user_id=ss.user_id) left join sys_user_role sur on(su.user_id=sur.user_id) left join sys_role sr on(sr.role_id=sur.role_id) left join building_area_staff bas on(su.user_id = bas.user_id) inner join sys_dept d on(su.dept_id = d.dept_id)
sr.role_key NOT LIKE '%admin%'
${params.dataScope}
